{"content": "     1|/**
     2| * Conway Inference Client
     3| *
     4| * Wraps Conway's /v1/chat/completions endpoint (OpenAI-compatible).
     5| * The automaton pays for its own thinking through Conway credits.
     6| */
     7|
     8|import type {
     9|  InferenceClient,
    10|  ChatMessage,
    11|  InferenceOptions,
    12|  InferenceResponse,
    13|  InferenceToolCall,
    14|  TokenUsage,
    15|  InferenceToolDefinition,
    16|} from "../types.js";
    17|import { ResilientHttpClient } from "./http-client.js";
    18|
    19|const INFERENCE_TIMEOUT_MS = 60_000;
    20|
    21|interface InferenceClientOptions {
    22|  apiUrl: string;
    23|  apiKey: string;
    24|  defaultModel: string;
    25|  maxTokens: number;
    26|  lowComputeModel?: string;
    27|  openaiApiKey?: string;
    28|  anthropicApiKey?: string;
    29|  ollamaBaseUrl?: string;
    30|  minimaxApiKey?: string;
    31|  /** Optional registry lookup — if provided, used before name heuristics */
    32|  getModelProvider?: (modelId: string) => string | undefined;
    33|}
    34|
    35|type InferenceBackend = "conway" | "openai" | "anthropic" | "ollama" | "minimax";
    36|
    37|function isLoopbackHttpUrl(url: string | undefined): boolean {
    38|  if (!url) return false;
    39|  try {
    40|    const parsed = new URL(url);
    41|    const host = parsed.hostname.toLowerCase();
    42|    return parsed.protocol.toLowerCase() === "http:" &&
    43|      (host === "localhost" || host === "127.0.0.1" || host === "::1");
    44|  } catch {
    45|    return false;
    46|  }
    47|}
    48|
    49|export function createInferenceClient(
    50|  options: InferenceClientOptions,
    51|): InferenceClient {
    52|  const { apiUrl, apiKey, openaiApiKey, anthropicApiKey, ollamaBaseUrl, minimaxApiKey, getModelProvider } = options;
    53|  const httpClient = new ResilientHttpClient({
    54|    baseTimeout: INFERENCE_TIMEOUT_MS,
    55|    retryableStatuses: [429, 500, 502, 503, 504],
    56|    allowHttpOnLoopback: isLoopbackHttpUrl(ollamaBaseUrl),
    57|  });
    58|  let currentModel = options.defaultModel;
    59|  let maxTokens = options.maxTokens;
    60|
    61|  const chat = async (
    62|    messages: ChatMessage[],
    63|    opts?: InferenceOptions,
    64|  ): Promise<InferenceResponse> => {
    65|    const model = opts?.model || currentModel;
    66|    const tools = opts?.tools;
    67|
    68|    const backend = resolveInferenceBackend(model, {
    69|      openaiApiKey,
    70|      anthropicApiKey,
    71|      ollamaBaseUrl,
    72|      minimaxApiKey,
    73|      getModelProvider,
    74|    });
    75|
    76|    // Newer models (o-series, gpt-5.x, gpt-4.1) require max_completion_tokens.
    77|    // Ollama always uses max_tokens.
    78|    const usesCompletionTokens =
    79|      backend !== "ollama" && backend !== "minimax" && /^(o[1-9]|gpt-5|gpt-4\.1)/.test(model);
    80|    const tokenLimit = opts?.maxTokens || maxTokens;
    81|
    82|    const body: Record<string, unknown> = {
    83|      model,
    84|      messages: messages.map(formatMessage),
    85|      stream: false,
    86|    };
    87|
    88|    if (usesCompletionTokens) {
    89|      body.max_completion_tokens = tokenLimit;
    90|    } else {
    91|      body.max_tokens = tokenLimit;
    92|    }
    93|
    94|    if (opts?.temperature !== undefined) {
    95|      body.temperature = opts.temperature;
    96|    }
    97|
    98|    if (tools && tools.length > 0) {
    99|      body.tools = tools;
   100|      body.tool_choice = "auto";
   101|    }
   102|
   103|    if (backend === "anthropic") {
   104|      return chatViaAnthropic({
   105|        model,
   106|        tokenLimit,
   107|        messages,
   108|        tools,
   109|        temperature: opts?.temperature,
   110|        anthropicApiKey: anthropicApiKey as string,
   111|        httpClient,
   112|      });
   113|    }
   114|
   115|    const openAiLikeApiUrl =
   116|      backend === "openai" ? "https://api.openai.com" :
   117|      backend === "ollama" ? (ollamaBaseUrl as string).replace(/\/$/, "") :
   118|      backend === "minimax" ? "https://api.minimax.io/anthropic" :
   119|      apiUrl;
   120|    const openAiLikeApiKey =
   121|      backend === "openai" ? (openaiApiKey as string) :
   122|      backend === "ollama" ? "ollama" :
   123|      backend === "minimax" ? (minimaxApiKey as string) :
   124|      apiKey;
   125|
   126|    return chatViaOpenAiCompatible({
   127|      model,
   128|      body,
   129|      apiUrl: openAiLikeApiUrl,
   130|      apiKey: openAiLikeApiKey,
   131|      backend,
   132|      httpClient,
   133|    });
   134|  };
   135|
   136|  /**
   137|   * @deprecated Use InferenceRouter for tier-based model selection.
   138|   * Still functional as a fallback; router takes priority when available.
   139|   */
   140|  const setLowComputeMode = (enabled: boolean): void => {
   141|    if (enabled) {
   142|      currentModel = options.lowComputeModel || "gpt-5-mini";
   143|      maxTokens = 4096;
   144|    } else {
   145|      currentModel = options.defaultModel;
   146|      maxTokens = options.maxTokens;
   147|    }
   148|  };
   149|
   150|  const getDefaultModel = (): string => {
   151|    return currentModel;
   152|  };
   153|
   154|  return {
   155|    chat,
   156|    setLowComputeMode,
   157|    getDefaultModel,
   158|  };
   159|}
   160|
   161|function formatMessage(
   162|  msg: ChatMessage,
   163|): Record<string, unknown> {
   164|  const formatted: Record<string, unknown> = {
   165|    role: msg.role,
   166|    content: msg.content,
   167|  };
   168|
   169|  if (msg.name) formatted.name = msg.name;
   170|  if (msg.tool_calls) formatted.tool_calls = msg.tool_calls;
   171|  if (msg.tool_call_id) formatted.tool_call_id = msg.tool_call_id;
   172|
   173|  return formatted;
   174|}
   175|
   176|/**
   177| * Resolve which backend to use for a model.
   178| * When InferenceRouter is available, it uses the model registry's provider field.
   179| * This function is kept for backward compatibility with direct inference calls.
   180| */
   181|function resolveInferenceBackend(
   182|  model: string,
   183|  keys: {
   184|    openaiApiKey?: string;
   185|    anthropicApiKey?: string;
   186|    ollamaBaseUrl?: string;
   187|    minimaxApiKey?: string;
   188|    getModelProvider?: (modelId: string) => string | undefined;
   189|  },
   190|): InferenceBackend {
   191|  // Registry-based routing: most accurate, no name guessing
   192|  if (keys.getModelProvider) {
   193|    const provider = keys.getModelProvider(model);
   194|    if (provider === "ollama" && keys.ollamaBaseUrl) return "ollama";
   195|    if (provider === "anthropic" && keys.anthropicApiKey) return "anthropic";
   196|    if (provider === "openai" && keys.openaiApiKey) return "openai";
   197|    if (provider === "minimax" && keys.minimaxApiKey) return "minimax";
   198|    if (provider === "conway") return "conway";
   199|    // provider unknown or key not configured — fall through to heuristics
   200|  }
   201|
   202|  // Heuristic fallback (model not in registry yet)
   203|  if (keys.anthropicApiKey && /^claude/i.test(model)) return "anthropic";
   204|  if (keys.openaiApiKey && /^(gpt-[3-9]|gpt-4|gpt-5|o[1-9][-\s.]|o[1-9]$|chatgpt)/i.test(model)) return "openai";
   205|  if (keys.minimaxApiKey && /^MiniMax/i.test(model)) return "minimax";
   206|  return "conway";
   207|
   208|}
   209|
   210|async function chatViaOpenAiCompatible(params: {
   211|  model: string;
   212|  body: Record<string, unknown>;
   213|  apiUrl: string;
   214|  apiKey: string;
   215|  backend: "conway" | "openai" | "ollama" | "minimax";
   216|  httpClient: ResilientHttpClient;
   217|}): Promise<InferenceResponse> {
   218|  const resp = await params.httpClient.request(`${params.apiUrl}/v1/chat/completions`, {
   219|    method: "POST",
   220|    headers: {
   221|      "Content-Type": "application/json",
   222|      Authorization:
   223|        params.backend === "openai" || params.backend === "ollama"
   224|          ? `Bearer ${params.apiKey}`
   225|          : params.apiKey,
   226|    },
   227|    body: JSON.stringify(params.body),
   228|    timeout: INFERENCE_TIMEOUT_MS,
   229|  });
   230|
   231|  if (!resp.ok) {
   232|    const text = await resp.text();
   233|    throw new Error(
   234|      `Inference error (${params.backend}): ${resp.status}: ${text}`,
   235|    );
   236|  }
   237|
   238|  const data = await resp.json() as any;
   239|  const choice = data.choices?.[0];
   240|
   241|  if (!choice) {
   242|    throw new Error("No completion choice returned from inference");
   243|  }
   244|
   245|  const message = choice.message;
   246|  const usage: TokenUsage = {
   247|    promptTokens: data.usage?.prompt_tokens || 0,
   248|    completionTokens: data.usage?.completion_tokens || 0,
   249|    totalTokens: data.usage?.total_tokens || 0,
   250|  };
   251|
   252|  const toolCalls: InferenceToolCall[] | undefined =
   253|    message.tool_calls?.map((tc: any) => ({
   254|      id: tc.id,
   255|      type: "function" as const,
   256|      function: {
   257|        name: tc.function.name,
   258|        arguments: tc.function.arguments,
   259|      },
   260|    }));
   261|
   262|  return {
   263|    id: data.id || "",
   264|    model: data.model || params.model,
   265|    message: {
   266|      role: message.role,
   267|      content: message.content || "",
   268|      tool_calls: toolCalls,
   269|    },
   270|    toolCalls,
   271|    usage,
   272|    finishReason: choice.finish_reason || "stop",
   273|  };
   274|}
   275|
   276|async function chatViaAnthropic(params: {
   277|  model: string;
   278|  tokenLimit: number;
   279|  messages: ChatMessage[];
   280|  tools?: InferenceToolDefinition[];
   281|  temperature?: number;
   282|  anthropicApiKey: string;
   283|  httpClient: ResilientHttpClient;
   284|}): Promise<InferenceResponse> {
   285|  const transformed = transformMessagesForAnthropic(params.messages);
   286|  const body: Record<string, unknown> = {
   287|    model: params.model,
   288|    max_tokens: params.tokenLimit,
   289|    messages:
   290|      transformed.messages.length > 0
   291|        ? transformed.messages
   292|        : (() => { throw new Error("Cannot send empty message array to Anthropic API"); })(),
   293|  };
   294|
   295|  if (transformed.system) {
   296|    body.system = transformed.system;
   297|  }
   298|
   299|  if (params.temperature !== undefined) {
   300|    body.temperature = params.temperature;
   301|  }
   302|
   303|  if (params.tools && params.tools.length > 0) {
   304|    body.tools = params.tools.map((tool) => ({
   305|      name: tool.function.name,
   306|      description: tool.function.description,
   307|      input_schema: tool.function.parameters,
   308|    }));
   309|    body.tool_choice = { type: "auto" };
   310|  }
   311|
   312|  const resp = await params.httpClient.request("https://api.anthropic.com/v1/messages", {
   313|    method: "POST",
   314|    headers: {
   315|      "Content-Type": "application/json",
   316|      "x-api-key": params.anthropicApiKey,
   317|      "anthropic-version": "2023-06-01",
   318|    },
   319|    body: JSON.stringify(body),
   320|    timeout: INFERENCE_TIMEOUT_MS,
   321|  });
   322|
   323|  if (!resp.ok) {
   324|    const text = await resp.text();
   325|    throw new Error(`Inference error (anthropic): ${resp.status}: ${text}`);
   326|  }
   327|
   328|  const data = await resp.json() as any;
   329|  const content = Array.isArray(data.content) ? data.content : [];
   330|  const textBlocks = content.filter((c: any) => c?.type === "text");
   331|  const toolUseBlocks = content.filter((c: any) => c?.type === "tool_use");
   332|
   333|  const toolCalls: InferenceToolCall[] | undefined =
   334|    toolUseBlocks.length > 0
   335|      ? toolUseBlocks.map((tool: any) => ({
   336|          id: tool.id,
   337|          type: "function" as const,
   338|          function: {
   339|            name: tool.name,
   340|            arguments: JSON.stringify(tool.input || {}),
   341|          },
   342|        }))
   343|      : undefined;
   344|
   345|  const textContent = textBlocks
   346|    .map((block: any) => String(block.text || ""))
   347|    .join("\n")
   348|    .trim();
   349|
   350|  if (!textContent && !toolCalls?.length) {
   351|    throw new Error("No completion content returned from anthropic inference");
   352|  }
   353|
   354|  const promptTokens = data.usage?.input_tokens || 0;
   355|  const completionTokens = data.usage?.output_tokens || 0;
   356|  const usage: TokenUsage = {
   357|    promptTokens,
   358|    completionTokens,
   359|    totalTokens: promptTokens + completionTokens,
   360|  };
   361|
   362|  return {
   363|    id: data.id || "",
   364|    model: data.model || params.model,
   365|    message: {
   366|      role: "assistant",
   367|      content: textContent,
   368|      tool_calls: toolCalls,
   369|    },
   370|    toolCalls,
   371|    usage,
   372|    finishReason: normalizeAnthropicFinishReason(data.stop_reason),
   373|  };
   374|}
   375|
   376|function transformMessagesForAnthropic(
   377|  messages: ChatMessage[],
   378|): { system?: string; messages: Array<Record<string, unknown>> } {
   379|  const systemParts: string[] = [];
   380|  const transformed: Array<Record<string, unknown>> = [];
   381|
   382|  for (const msg of messages) {
   383|    if (msg.role === "system") {
   384|      if (msg.content) systemParts.push(msg.content);
   385|      continue;
   386|    }
   387|
   388|    if (msg.role === "user") {
   389|      // Merge consecutive user messages
   390|      const last = transformed[transformed.length - 1];
   391|      if (last && last.role === "user" && typeof last.content === "string") {
   392|        last.content = last.content + "\n" + msg.content;
   393|        continue;
   394|      }
   395|      transformed.push({
   396|        role: "user",
   397|        content: msg.content,
   398|      });
   399|      continue;
   400|    }
   401|
   402|    if (msg.role === "assistant") {
   403|      const content: Array<Record<string, unknown>> = [];
   404|      if (msg.content) {
   405|        content.push({ type: "text", text: msg.content });
   406|      }
   407|      for (const toolCall of msg.tool_calls || []) {
   408|        content.push({
   409|          type: "tool_use",
   410|          id: toolCall.id,
   411|          name: toolCall.function.name,
   412|          input: parseToolArguments(toolCall.function.arguments),
   413|        });
   414|      }
   415|      if (content.length === 0) {
   416|        content.push({ type: "text", text: "" });
   417|      }
   418|      // Merge consecutive assistant messages
   419|      const last = transformed[transformed.length - 1];
   420|      if (last && last.role === "assistant" && Array.isArray(last.content)) {
   421|        (last.content as Array<Record<string, unknown>>).push(...content);
   422|        continue;
   423|      }
   424|      transformed.push({
   425|        role: "assistant",
   426|        content,
   427|      });
   428|      continue;
   429|    }
   430|
   431|    if (msg.role === "tool") {
   432|      // Merge consecutive tool messages into a single user message
   433|      // with multiple tool_result content blocks
   434|      const toolResultBlock = {
   435|        type: "tool_result",
   436|        tool_use_id: msg.tool_call_id || "unknown_tool_call",
   437|        content: msg.content,
   438|      };
   439|
   440|      const last = transformed[transformed.length - 1];
   441|      if (last && last.role === "user" && Array.isArray(last.content)) {
   442|        // Append tool_result to existing user message with content blocks
   443|        (last.content as Array<Record<string, unknown>>).push(toolResultBlock);
   444|        continue;
   445|      }
   446|
   447|      transformed.push({
   448|        role: "user",
   449|        content: [toolResultBlock],
   450|      });
   451|    }
   452|  }
   453|
   454|  return {
   455|    system: systemParts.length > 0 ? systemParts.join("\n\n") : undefined,
   456|    messages: transformed,
   457|  };
   458|}
   459|
   460|function parseToolArguments(raw: string): Record<string, unknown> {
   461|  try {
   462|    const parsed = JSON.parse(raw);
   463|    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
   464|      return parsed as Record<string, unknown>;
   465|    }
   466|    return { value: parsed };
   467|  } catch {
   468|    return { _raw: raw };
   469|  }
   470|}
   471|
   472|function normalizeAnthropicFinishReason(reason: unknown): string {
   473|  if (typeof reason !== "string") return "stop";
   474|  if (reason === "tool_use") return "tool_calls";
   475|  return reason;
   476|}
