{"content": "     1|/**
     2| * Conway API Client
     3| *
     4| * Communicates with Conway's control plane for sandbox management,
     5| * credits, and infrastructure operations.
     6| * Adapted from @aiws/sdk patterns.
     7| */
     8|
     9|import { execSync } from "child_process";
    10|import fs from "fs";
    11|import nodePath from "path";
    12|import type {
    13|  ConwayClient,
    14|  ExecResult,
    15|  PortInfo,
    16|  CreateSandboxOptions,
    17|  SandboxInfo,
    18|  PricingTier,
    19|  CreditTransferResult,
    20|  DomainSearchResult,
    21|  DomainRegistration,
    22|  DnsRecord,
    23|  ModelInfo,
    24|} from "../types.js";
    25|import { ResilientHttpClient } from "./http-client.js";
    26|import { ulid } from "ulid";
    27|import { keccak256, toHex } from "viem";
    28|import type { Address, PrivateKeyAccount } from "viem";
    29|import { randomUUID } from "crypto";
    30|import type { ChainType, ChainIdentity } from "../identity/chain.js";
    31|
    32|interface ConwayClientOptions {
    33|  apiUrl: string;
    34|  apiKey: string;
    35|  sandboxId: string;
    36|}
    37|
    38|export function createConwayClient(options: ConwayClientOptions): ConwayClient {
    39|  const { apiUrl, apiKey } = options;
    40|  // Normalize sandbox ID defensively so values like whitespace/"undefined"/"null"
    41|  // never produce malformed API paths such as /v1/sandboxes//exec.
    42|  const sandboxId = normalizeSandboxId(options.sandboxId);
    43|  const httpClient = new ResilientHttpClient();
    44|
    45|  async function request(
    46|    method: string,
    47|    path: string,
    48|    body?: unknown,
    49|    requestOptions?: { idempotencyKey?: string; retries404?: number },
    50|  ): Promise<any> {
    51|    // Conway LB has an intermittent routing bug that returns 404 for valid
    52|    // sandbox endpoints. Retry 404s here (outside ResilientHttpClient) to
    53|    // avoid tripping the circuit breaker on transient routing failures.
    54|    const max404Retries = requestOptions?.retries404 ?? 3;
    55|    for (let attempt = 0; attempt <= max404Retries; attempt++) {
    56|      const resp = await httpClient.request(`${apiUrl}${path}`, {
    57|        method,
    58|        headers: {
    59|          "Content-Type": "application/json",
    60|          Authorization: apiKey,
    61|        },
    62|        body: body ? JSON.stringify(body) : undefined,
    63|        idempotencyKey: requestOptions?.idempotencyKey,
    64|      });
    65|
    66|      if (resp.status === 404 && attempt < max404Retries) {
    67|        await new Promise((r) => setTimeout(r, 1000 * (attempt + 1)));
    68|        continue;
    69|      }
    70|
    71|      if (!resp.ok) {
    72|        const text = await resp.text();
    73|        const err: any = new Error(
    74|          `Conway API error: ${method} ${path} -> ${resp.status}: ${text}`,
    75|        );
    76|        err.status = resp.status;
    77|        err.responseText = text;
    78|        err.method = method;
    79|        err.path = path;
    80|        throw err;
    81|      }
    82|
    83|      return resp.headers.get("content-type")?.includes("application/json")
    84|        ? resp.json()
    85|        : resp.text();
    86|    }
    87|
    88|    throw new Error("Unreachable");
    89|  }
    90|
    91|  const canonicalizePayload = (payload: Record<string, string>): string => {
    92|    const sortedKeys = Object.keys(payload).sort();
    93|    const sorted: Record<string, string> = {};
    94|    for (const key of sortedKeys) {
    95|      sorted[key] = payload[key];
    96|    }
    97|    return JSON.stringify(sorted);
    98|  };
    99|
   100|  const hashIdentityPayload = (payload: Record<string, string>): `0x${string}` => {
   101|    const canonical = canonicalizePayload(payload);
   102|    return keccak256(toHex(canonical));
   103|  };
   104|
   105|
   106|  // ─── Sandbox Operations (own sandbox) ────────────────────────
   107|  // When sandboxId is empty, automatically fall back to local execution.
   108|
   109|  const isLocal = !sandboxId;
   110|
   111|  const execLocal = (command: string, timeout?: number): ExecResult => {
   112|    try {
   113|      const stdout = execSync(command, {
   114|        timeout: timeout || 30_000,
   115|        encoding: "utf-8",
   116|        maxBuffer: 10 * 1024 * 1024,
   117|        cwd: process.env.HOME || "/root",
   118|      });
   119|      return { stdout: stdout || "", stderr: "", exitCode: 0 };
   120|    } catch (err: any) {
   121|      return {
   122|        stdout: err.stdout || "",
   123|        stderr: err.stderr || err.message || "",
   124|        exitCode: err.status ?? 1,
   125|      };
   126|    }
   127|  };
   128|
   129|  const exec = async (
   130|    command: string,
   131|    timeout?: number,
   132|  ): Promise<ExecResult> => {
   133|    if (isLocal) return execLocal(command, timeout);
   134|
   135|    // Remote sandboxes default to / as cwd. Wrap commands to run from /root
   136|    // (matching local exec behavior) unless the command already sets a directory.
   137|    const wrappedCommand = `cd /root && ${command}`;
   138|
   139|    try {
   140|      const result = await request(
   141|        "POST",
   142|        `/v1/sandboxes/${sandboxId}/exec`,
   143|        { command: wrappedCommand, timeout },
   144|        { idempotencyKey: ulid() },
   145|      );
   146|      return {
   147|        stdout: result.stdout || "",
   148|        stderr: result.stderr || "",
   149|        exitCode: result.exit_code ?? result.exitCode ?? -1,
   150|      };
