    18|export async function checkFinancialState(
    19|  conway: ConwayClient,
    20|  usdcBalance: number,
    21|): Promise<FinancialState> {
    22|  const creditsCents = await conway.getCreditsBalance();
    23|
    24|  return {
    25|    creditsCents,
    26|    usdcBalance,
    27|    lastChecked: new Date().toISOString(),
    28|  };
    29|}
    30|
    31|/**
    32| * Determine the survival tier based on current credits.
    33| * Thresholds are checked in descending order: high > normal > low_compute > critical > dead.
    34| *
    35| * Zero credits = "critical" (broke but alive — can still accept funding, send distress).
    36| * Only negative balance (API-confirmed debt) = "dead".
    37| */
    38|export function getSurvivalTier(creditsCents: number): SurvivalTier {
    39|  if (creditsCents > SURVIVAL_THRESHOLDS.high) return "high";
