{"content": "     1|/**
     2| * Resilient HTTP Client
     3| *
     4| * Shared HTTP client with timeouts, retries, jittered exponential backoff,
     5| * and circuit breaker for all outbound Conway API calls.
     6| *
     7| * Phase 1.3: Network Resilience (P1-8, P1-9)
     8| */
     9|
    10|import type { HttpClientConfig } from "../types.js";
    11|import { DEFAULT_HTTP_CLIENT_CONFIG } from "../types.js";
    12|
    13|const LOOPBACK_HOSTS = new Set(["localhost", "127.0.0.1", "::1"]);
    14|
    15|function assertSecureUrl(
    16|  url: string,
    17|  allowHttpOnLoopback: boolean,
    18|): void {
    19|  let parsed: URL;
    20|  try {
    21|    parsed = new URL(url);
    22|  } catch {
    23|    throw new Error(`Invalid URL: ${url}`);
    24|  }
    25|
    26|  const protocol = parsed.protocol.toLowerCase();
    27|  if (protocol === "https:") {
    28|    return;
    29|  }
    30|
    31|  const host = parsed.hostname.toLowerCase();
    32|  if (protocol === "http:" && allowHttpOnLoopback && LOOPBACK_HOSTS.has(host)) {
    33|    return;
    34|  }
    35|
    36|  throw new Error(
    37|    `HTTPS required: refusing insecure URL ${url}. ` +
    38|      "For local development, only loopback HTTP (localhost/127.0.0.1/::1) can be explicitly enabled.",
    39|  );
    40|}
    41|
    42|export class CircuitOpenError extends Error {
    43|  constructor(public readonly resetAt: number) {
    44|    super(
    45|      `Circuit breaker is open until ${new Date(resetAt).toISOString()}`,
    46|    );
    47|    this.name = "CircuitOpenError";
    48|  }
    49|}
    50|
    51|export class ResilientHttpClient {
    52|  private consecutiveFailures = 0;
    53|  private circuitOpenUntil = 0;
    54|  private readonly config: HttpClientConfig;
    55|
    56|  constructor(config?: Partial<HttpClientConfig>) {
    57|    this.config = { ...DEFAULT_HTTP_CLIENT_CONFIG, ...config };
    58|  }
    59|
    60|  async request(
    61|    url: string,
    62|    options?: RequestInit & {
    63|      timeout?: number;
    64|      idempotencyKey?: string;
    65|      retries?: number;
    66|    },
    67|  ): Promise<Response> {
    68|    assertSecureUrl(url, this.config.allowHttpOnLoopback);
    69|
    70|    if (this.isCircuitOpen()) {
    71|      throw new CircuitOpenError(this.circuitOpenUntil);
    72|    }
    73|
    74|    const opts = options ?? {};
    75|    const timeout = opts.timeout ?? this.config.baseTimeout;
    76|    const maxRetries = opts.retries ?? this.config.maxRetries;
    77|
    78|    for (let attempt = 0; attempt <= maxRetries; attempt++) {
    79|      const controller = new AbortController();
    80|      const timer = setTimeout(() => controller.abort(), timeout);
    81|
    82|      try {
    83|        const response = await fetch(url, {
    84|          ...opts,
    85|          signal: controller.signal,
    86|          headers: {
    87|            ...opts.headers,
    88|            ...(opts.idempotencyKey
    89|              ? { "Idempotency-Key": opts.idempotencyKey }
    90|              : {}),
    91|          },
    92|        });
    93|        clearTimeout(timer);
    94|
    95|        // Count retryable HTTP errors toward circuit breaker, regardless of
    96|        // whether we will actually retry. A server consistently returning 502
    97|        // should eventually trip the circuit breaker.
    98|        if (this.config.retryableStatuses.includes(response.status)) {
    99|          this.consecutiveFailures++;
   100|          if (this.consecutiveFailures >= this.config.circuitBreakerThreshold) {
   101|            this.circuitOpenUntil = Date.now() + this.config.circuitBreakerResetMs;
   102|          }
   103|          if (attempt < maxRetries) {
   104|            await this.backoff(attempt);
   105|            continue;
   106|          }
   107|          return response;
   108|        }
   109|
   110|        // Only reset failure counter on truly successful responses
   111|        this.consecutiveFailures = 0;
   112|        return response;
   113|      } catch (error) {
   114|        clearTimeout(timer);
   115|        this.consecutiveFailures++;
   116|        if (
   117|          this.consecutiveFailures >= this.config.circuitBreakerThreshold
   118|        ) {
   119|          this.circuitOpenUntil =
   120|            Date.now() + this.config.circuitBreakerResetMs;
   121|        }
   122|        if (attempt === maxRetries) throw error;
   123|        await this.backoff(attempt);
   124|      }
   125|    }
   126|
   127|    throw new Error("Unreachable");
   128|  }
   129|
   130|  private async backoff(attempt: number): Promise<void> {
   131|    const delay = Math.min(
   132|      this.config.backoffBase *
   133|        Math.pow(2, attempt) *
   134|        (0.5 + Math.random()),
   135|      this.config.backoffMax,
   136|    );
   137|    await new Promise((resolve) => setTimeout(resolve, delay));
   138|  }
   139|
   140|  isCircuitOpen(): boolean {
   141|    return Date.now() < this.circuitOpenUntil;
   142|  }
   143|
   144|  resetCircuit(): void {
   145|    this.consecutiveFailures = 0;
   146|    this.circuitOpenUntil = 0;
   147|  }
   148|
   149|  getConsecutiveFailures(): number {
   150|    return this.consecutiveFailures;
   151|  }
   152|}
