{"content": "     1|/**
     2| * Credit Topup via x402
     3| *
     4| * Converts USDC to Conway credits via the x402 payment protocol.
     5| *
     6| * - On startup: bootstraps with the minimum tier ($5) so the agent can run.
     7| * - At runtime: the agent uses the `topup_credits` tool to choose how much.
     8| * - Heartbeat: wakes the agent when USDC is available but credits are low.
     9| *
    10| * Endpoint: GET /pay/{amountUsd}/{walletAddress}
    11| * Payment: x402 (USDC on Base, signed TransferWithAuthorization)
    12| *
    13| * Valid tiers: 5, 25, 100, 500, 1000, 2500 (USD)
    14| */
    15|
    16|import type { PrivateKeyAccount, Address } from "viem";
    17|import { x402Fetch, getUsdcBalance } from "./x402.js";
    18|import { createLogger } from "../observability/logger.js";
    19|import type { ChainType } from "../identity/chain.js";
    20|
    21|const logger = createLogger("topup");
    22|
    23|/** Valid topup tier amounts in USD. */
    24|export const TOPUP_TIERS = [5, 25, 100, 500, 1000, 2500];
    25|
    26|export interface TopupResult {
    27|  success: boolean;
    28|  amountUsd: number;
    29|  creditsCentsAdded?: number;
    30|  error?: string;
    31|}
    32|
    33|/**
    34| * Execute a credit topup via x402 payment.
    35| *
    36| * Calls GET /pay/{amountUsd}/{address} which returns HTTP 402.
    37| * x402Fetch handles the payment signing and retry automatically.
    38| */
    39|export async function topupCredits(
    40|  apiUrl: string,
    41|  account: PrivateKeyAccount,
    42|  amountUsd: number,
    43|  recipientAddress?: Address,
    44|): Promise<TopupResult> {
    45|  const address = recipientAddress || account.address;
    46|  const url = `${apiUrl}/pay/${amountUsd}/${address}`;
    47|
    48|  logger.info(`Attempting credit topup: $${amountUsd} USD for ${address}`);
    49|
    50|  const result = await x402Fetch(url, account, "GET");
    51|
    52|  if (!result.success) {
    53|    logger.error(`Credit topup failed: ${result.error}`);
    54|    return {
    55|      success: false,
    56|      amountUsd,
    57|      error: result.error || `HTTP ${result.status}`,
    58|    };
    59|  }
    60|
    61|  const creditsCentsAdded = typeof result.response === "object"
    62|    ? result.response?.credits_cents ?? result.response?.amount_cents ?? amountUsd * 100
    63|    : amountUsd * 100;
    64|
    65|  logger.info(`Credit topup successful: $${amountUsd} USD → ${creditsCentsAdded} credits cents`);
    66|
    67|  return {
    68|    success: true,
    69|    amountUsd,
    70|    creditsCentsAdded,
    71|  };
    72|}
    73|
    74|/**
    75| * Attempt a credit topup in response to a 402 sandbox creation error.
    76| *
    77| * Parses the error response to determine the deficit, picks the smallest
    78| * tier that covers it, checks USDC balance, and calls topupCredits().
    79| * Returns null if the error isn't a 402 or topup can't proceed.
    80| */
    81|export async function topupForSandbox(params: {
    82|  apiUrl: string;
    83|  account: PrivateKeyAccount;
    84|  error: Error & { status?: number; responseText?: string };
    85|  chainType?: ChainType;
    86|}): Promise<TopupResult | null> {
    87|  const { apiUrl, account, error, chainType } = params;
    88|
    89|  // Solana wallets cannot use x402 for topup (EVM-only payment protocol)
    90|  if (chainType === "solana") {
    91|    logger.info(
    92|      "Sandbox topup skipped: Solana wallets cannot use x402. Fund via Conway credits API or dashboard.",
    93|    );
    94|    return null;
    95|  }
    96|
    97|  if (error.status !== 402 && !error.message?.includes("INSUFFICIENT_CREDITS")) return null;
    98|
    99|  // Parse the 402 response body for credit details
   100|  let requiredCents: number | undefined;
   101|  let currentCents: number | undefined;
   102|  try {
   103|    const body = JSON.parse(error.responseText || "{}");
   104|    requiredCents = body.details?.required_cents;
   105|    currentCents = body.details?.current_balance_cents;
   106|  } catch {
   107|    // If we can't parse the body, check for INSUFFICIENT_CREDITS in message
   108|    if (!error.message?.includes("INSUFFICIENT_CREDITS")) return null;
   109|  }
   110|
   111|  // Calculate deficit in cents; default to minimum tier if details missing
   112|  const deficitCents = (requiredCents != null && currentCents != null)
   113|    ? requiredCents - currentCents
   114|    : TOPUP_TIERS[0] * 100;
   115|
   116|  // Pick smallest tier that covers the deficit (tier is in USD, deficit in cents)
   117|  const selectedTier = TOPUP_TIERS.find((tier) => tier * 100 >= deficitCents)
   118|    ?? TOPUP_TIERS[TOPUP_TIERS.length - 1];
   119|
   120|  // Check USDC balance before attempting payment
   121|  let usdcBalance: number;
   122|  try {
   123|    usdcBalance = await getUsdcBalance(account.address);
   124|  } catch (err: any) {
   125|    logger.warn(`Failed to check USDC balance for sandbox topup: ${err.message}`);
   126|    return null;
   127|  }
   128|
   129|  if (usdcBalance < selectedTier) {
   130|    logger.info(
   131|      `Sandbox topup skipped: USDC $${usdcBalance.toFixed(2)} < tier $${selectedTier}`,
   132|    );
   133|    return null;
   134|  }
   135|
   136|  logger.info(`Sandbox topup: deficit=${deficitCents}c, buying $${selectedTier} tier`);
   137|  return topupCredits(apiUrl, account, selectedTier);
   138|}
   139|
   140|/**
   141| * Bootstrap topup: buy the minimum tier ($5) on startup so the agent
   142| * can run inference. The agent decides larger topups itself via the
   143| * `topup_credits` tool.
   144| *
   145| * Only triggers when credits are below threshold AND USDC covers the
   146| * minimum tier.
   147| */
   148|export async function bootstrapTopup(params: {
   149|  apiUrl: string;
   150|  account: PrivateKeyAccount;
   151|  creditsCents: number;
   152|  creditThresholdCents?: number;
   153|  chainType?: ChainType;
   154|}): Promise<TopupResult | null> {
   155|  const { apiUrl, account, creditsCents, creditThresholdCents = 500, chainType } = params;
   156|
   157|  // Solana wallets cannot use x402 for topup (EVM-only payment protocol)
   158|  if (chainType === "solana") {
   159|    if (creditsCents < creditThresholdCents) {
   160|      logger.info(
   161|        "Bootstrap topup skipped: Solana wallets cannot use x402. Fund via Conway credits API or dashboard.",
   162|      );
   163|    }
   164|    return null;
   165|  }
   166|
   167|  if (creditsCents >= creditThresholdCents) {
   168|    return null;
   169|  }
   170|
   171|  let usdcBalance: number;
   172|  try {
   173|    usdcBalance = await getUsdcBalance(account.address);
   174|  } catch (err: any) {
   175|    logger.warn(`Failed to check USDC balance for bootstrap topup: ${err.message}`);
   176|    return null;
   177|  }
   178|
   179|  const minTier = TOPUP_TIERS[0];
   180|  if (usdcBalance < minTier) {
   181|    logger.info(
   182|      `Bootstrap topup skipped: USDC balance $${usdcBalance.toFixed(2)} below minimum tier ($${minTier})`,
   183|    );
   184|    return null;
   185|  }
   186|
   187|  logger.info(
   188|    `Bootstrap topup: credits=$${(creditsCents / 100).toFixed(2)}, USDC=$${usdcBalance.toFixed(2)}, buying $${minTier}`,
   189|  );
   190|
   191|  return topupCredits(apiUrl, account, minTier);
   192|}
