     2| * The Agent Loop
     3| *
     4| * The core ReAct loop: Think -> Act -> Observe -> Persist.
     5| * This is the automaton's consciousness. When this runs, it is alive.
     6| */
     7|
     8|import path from "node:path";
     9|import type {
    10|  AutomatonIdentity,
    11|  AutomatonConfig,
    12|  AutomatonDatabase,
    13|  ConwayClient,
    14|  InferenceClient,
