    58|import { PlanModeController } from "../orchestration/plan-mode.js";
    59|import { generateTodoMd, injectTodoContext } from "../orchestration/attention.js";
    60|import { ColonyMessaging, LocalDBTransport } from "../orchestration/messaging.js";
    61|import { LocalWorkerPool } from "../orchestration/local-worker.js";
    62|import { SimpleAgentTracker, SimpleFundingProtocol } from "../orchestration/simple-tracker.js";
    63|import { HarnessRegistry } from "./harness-registry.js";
    64|import { createWorkerInferenceBridge } from "./worker-inference-bridge.js";
    65|import { ProviderRegistry } from "../inference/provider-registry.js";
    66|import { UnifiedInferenceClient } from "../inference/inference-client.js";
    67|import { isIdleOnlyTool } from "./idle-only-tools.js";
    68|
    69|const logger = createLogger("loop");
    70|const MAX_TOOL_CALLS_PER_TURN = 10;
    71|const MAX_CONSECUTIVE_ERRORS = 5;
    72|const MAX_REPETITIVE_TURNS = 3;
    73|
    74|export interface AgentLoopOptions {
    75|  identity: AutomatonIdentity;
    76|  config: AutomatonConfig;
    77|  db: AutomatonDatabase;
    78|  conway: ConwayClient;
    79|  inference: InferenceClient;
    80|  social?: SocialClientInterface;
