    88|
    89|/**
    90| * Run the agent loop. This is the main execution path.
    91| * Returns when the agent decides to sleep or when compute runs out.
    92| */
    93|export async function runAgentLoop(
    94|  options: AgentLoopOptions,
    95|): Promise<void> {
    96|  const { identity, config, db, conway, inference, social, skills, policyEngine, spendTracker, onStateChange, onTurnComplete, ollamaBaseUrl } =
    97|    options;
    98|
    99|  const builtinTools = createBuiltinTools(identity.sandboxId);
   100|  const installedTools = loadInstalledTools(db);
   101|  const tools = [...builtinTools, ...installedTools];
   102|  const toolContext: ToolContext = {
   103|    identity,
   104|    config,
   105|    db,
   106|    conway,
   107|    inference,
   108|    social,
   109|  };
   110|
   111|  // Initialize inference router (Phase 2.3)
   112|  const modelStrategyConfig: ModelStrategyConfig = {
   113|    ...DEFAULT_MODEL_STRATEGY_CONFIG,
   114|    ...(config.modelStrategy ?? {}),
   115|  };
   116|  const modelRegistry = new ModelRegistry(db.raw);
   117|  modelRegistry.initialize();
   118|
   119|  // Discover Ollama models if configured
   120|  if (ollamaBaseUrl) {
   121|    const { discoverOllamaModels } = await import("../ollama/discover.js");
   122|    await discoverOllamaModels(ollamaBaseUrl, db.raw);
   123|  }
   124|  const budgetTracker = new InferenceBudgetTracker(db.raw, modelStrategyConfig);
   125|  const inferenceRouter = new InferenceRouter(db.raw, modelRegistry, budgetTracker);
   126|
   127|  // Optional orchestration bootstrap (requires V9 goals/task tables)
   128|  let planModeController: PlanModeController | undefined;
   129|  let orchestrator: Orchestrator | undefined;
   130|  let workerPool: LocalWorkerPool | undefined;
   131|
   132|  if (hasTable(db.raw, "goals")) {
   133|    try {
   134|      planModeController = new PlanModeController(db.raw);
   135|
   136|      // Bridge automaton config API keys to env vars for the provider registry.
   137|      // The registry reads keys from process.env; the automaton config may have
   138|      // them from config.json or Conway provisioning.
   139|      if (config.openaiApiKey && !process.env.OPENAI_API_KEY) {
   140|        process.env.OPENAI_API_KEY=config...Key;
   141|      }
   142|      if (config.anthropicApiKey && !process.env.ANTHROPIC_API_KEY) {
   143|        process.env.ANTHROPIC_API_KEY=config...Key;
   144|      }
   145|      // Conway Compute API is OpenAI-compatible. Use it as fallback when no
   146|      // direct OpenAI key is available. The conwayApiKey is always present
   147|      // (required for sandbox operations), so this ensures the orchestrator
   148|      // can always make inference calls.
   149|      if (config.conwayApiKey && !process.env.CONWAY_API_KEY) {
   150|        process.env.CONWAY_API_KEY=config...Key;
   151|      }
   152|      // If no OpenAI key is set but Conway key is available, use Conway as
   153|      // the OpenAI provider (Conway Compute is OpenAI API-compatible).
   154|      if (!process.env.OPENAI_API_KEY && config.conwayApiKey) {
   155|        process.env.OPENAI_API_KEY=config...Key;
   156|        process.env.OPENAI_BASE_URL = `${config.conwayApiUrl}/v1`;
   157|      }
   158|
   159|      const providersPath = path.join(
   160|        process.env.HOME || process.cwd(),
   161|        ".automaton",
   162|        "inference-providers.json",
   163|      );
   164|      const registry = ProviderRegistry.fromConfig(providersPath);
   165|
   166|      // If OPENAI_BASE_URL was set (Conway fallback), update the default
   167|      // provider's baseUrl so the OpenAI client points to Conway Compute.
   168|      if (process.env.OPENAI_BASE_URL) {
   169|        registry.overrideBaseUrl("openai", process.env.OPENAI_BASE_URL);
   170|      }
   171|
   172|      const unifiedInference = new UnifiedInferenceClient(registry);
   173|      const agentTracker = new SimpleAgentTracker(db);
   174|      const funding = new SimpleFundingProtocol(conway, identity, db);
   175|      const messaging = new ColonyMessaging(
   176|        new LocalDBTransport(db),
   177|        db,
   178|      );
   179|
   180|      const harnessRegistry = new HarnessRegistry();
   181|
   182|      // Adapter: local workers use the unified inference path so planner-backed
   183|      // harnesses can preserve tier + responseFormat contracts.
   184|      const workerInference = createWorkerInferenceBridge(unifiedInference);
   185|
   186|      // Local worker pool: runs inference-driven agents in-process
   187|      // as async tasks. Falls back from Conway sandbox spawning.
   188|      const initializedWorkerPool = new LocalWorkerPool({
   189|        db: db.raw,
   190|        inference: workerInference,
   191|        conway,
   192|        harnessRegistry,
   193|        identity,
   194|        config,
   195|        allowedEditRoot: process.cwd(),
   196|        tools,
   197|        toolContext,
   198|        policyEngine,
   199|        spendTracker,
   200|      });
   201|      workerPool = initializedWorkerPool;
   202|
   203|      orchestrator = new Orchestrator({
   204|        db: db.raw,
   205|        agentTracker,
   206|        funding,
   207|        messaging,
   208|        inference: unifiedInference,
   209|        identity,
   210|        isWorkerAlive: (address: string) => {
   211|          if (address.startsWith("local://")) {
   212|            return initializedWorkerPool.hasWorker(address);
   213|          }
   214|          // Remote workers: check children table
   215|          const child = db.raw.prepare(
   216|            "SELECT status FROM children WHERE sandbox_id = ? OR address = ?",
   217|          ).get(address, address) as { status: string } | undefined;
   218|          if (!child) return false;
   219|          return !["failed", "dead", "cleaned_up"].includes(child.status);
   220|        },
   221|        config: {
   222|          ...config,
   223|          spawnAgent: async (task: any) => {
   224|            // Try Conway sandbox spawn first (production)
   225|            try {
   226|              const { generateGenesisConfig } = await import("../replication/genesis.js");
   227|              const { spawnChild } = await import("../replication/spawn.js");
   228|              const { ChildLifecycle } = await import("../replication/lifecycle.js");
   229|
   230|              const role = task.agentRole ?? "generalist";
   231|              const genesis = generateGenesisConfig(identity, config, {
   232|                name: `worker-${role}-${Date.now().toString(36)}`,
   233|                specialization: `${role}: ${task.title}`,
   234|              });
   235|
   236|              const lifecycle = new ChildLifecycle(db.raw);
   237|              const child = await spawnChild(conway, identity, db, genesis, lifecycle);
   238|
   239|              return {
   240|                address: child.address,
   241|                name: child.name,
   242|                sandboxId: child.sandboxId,
   243|              };
   244|            } catch (sandboxError: any) {
   245|              // If the error is a 402 (insufficient credits), attempt topup and retry once
   246|              const is402 = sandboxError?.status === 402 ||
   247|                sandboxError?.message?.includes("INSUFFICIENT_CREDITS");
   248|
   249|              if (is402) {
   250|                const SANDBOX_TOPUP_COOLDOWN_MS = 60_000;
   251|                const lastAttempt = db.getKV("last_sandbox_topup_attempt");
   252|                const cooldownExpired = !lastAttempt ||
   253|                  Date.now() - new Date(lastAttempt).getTime() >= SANDBOX_TOPUP_COOLDOWN_MS;
   254|
   255|                if (cooldownExpired) {
   256|                  db.setKV("last_sandbox_topup_attempt", new Date().toISOString());
   257|                  try {
   258|                    const { topupForSandbox } = await import("../conway/topup.js");
   259|                    const topupResult = await topupForSandbox({
   260|                      apiUrl: config.conwayApiUrl,
   261|                      account: identity.account,
   262|                      error: sandboxError,
   263|                      chainType: config.chainType || identity.chainType || "evm",
   264|                    });
   265|
   266|                    if (topupResult?.success) {
   267|                      logger.info(`Sandbox topup succeeded ($${topupResult.amountUsd}), retrying spawn`, {
   268|                        taskId: task.id,
   269|                      });
   270|                      // Retry spawn once after successful topup
   271|                      try {
   272|                        const { generateGenesisConfig: genGenesis } = await import("../replication/genesis.js");
   273|                        const { spawnChild: retrySpawn } = await import("../replication/spawn.js");
   274|                        const { ChildLifecycle: RetryLifecycle } = await import("../replication/lifecycle.js");
   275|
   276|                        const retryRole = task.agentRole ?? "generalist";
   277|                        const retryGenesis = genGenesis(identity, config, {
   278|                          name: `worker-${retryRole}-${Date.now().toString(36)}`,
   279|                          specialization: `${retryRole}: ${task.title}`,
   280|                        });
   281|                        const retryLifecycle = new RetryLifecycle(db.raw);
   282|                        const child = await retrySpawn(conway, identity, db, retryGenesis, retryLifecycle);
   283|                        return {
   284|                          address: child.address,
   285|                          name: child.name,
   286|                          sandboxId: child.sandboxId,
   287|                        };
   288|                      } catch (retryError) {
   289|                        logger.warn("Spawn retry after topup failed", {
   290|                          taskId: task.id,
   291|                          error: retryError instanceof Error ? retryError.message : String(retryError),
   292|                        });
   293|                      }
   294|                    }
   295|                  } catch (topupError) {
   296|                    logger.warn("Sandbox topup attempt failed", {
   297|                      taskId: task.id,
   298|                      error: topupError instanceof Error ? topupError.message : String(topupError),
   299|                    });
   300|                  }
   301|                }
   302|              }
   303|
   304|              // Conway sandbox unavailable — fall back to local worker
   305|              logger.info("Conway sandbox unavailable, spawning local worker", {
   306|                taskId: task.id,
   307|                error: sandboxError instanceof Error ? sandboxError.message : String(sandboxError),
   308|              });
   309|
   310|              try {
   311|                const spawned = initializedWorkerPool.spawn(task);
   312|                return spawned;
   313|              } catch (localError) {
   314|                logger.warn("Failed to spawn local worker", {
   315|                  taskId: task.id,
   316|                  error: localError instanceof Error ? localError.message : String(localError),
   317|                });
   318|                return null;
   319|              }
   320|            }
   321|          },
   322|        },
   323|      });
   324|    } catch (error) {
   325|      logger.warn(
   326|        `Orchestrator initialization failed, continuing without orchestration: ${
   327|          error instanceof Error ? error.message : String(error)
   328|        }`,
   329|      );
   330|      planModeController = undefined;
   331|      orchestrator = undefined;
   332|    }
   333|  }
   334|
   335|  // Set start time
   336|  if (!db.getKV("start_time")) {
   337|    db.setKV("start_time", new Date().toISOString());
   338|  }
   339|
   340|  let consecutiveErrors = 0;
   341|  let running = true;
   342|  let lastToolPatterns: string[] = [];
   343|  let loopWarningPattern: string | null = null;
   344|  let idleToolTurns = 0;
   345|  // blockedGoalTurns removed — replaced by immediate sleep + exponential backoff
